import{_ as r,c as a,o as l,ag as t}from"./chunks/framework.DPDPlp3K.js";const i="/assets/1736149676339.D5oWoHFH.png",o="/assets/1737202214559.D9oi2sAY.png",b=JSON.parse('{"title":"如何描述一个化学物质","description":"","frontmatter":{},"headers":[],"relativePath":"分子模拟/背景知识/化学物质.md","filePath":"分子模拟/背景知识/化学物质.md","lastUpdated":null}'),n={name:"分子模拟/背景知识/化学物质.md"};function h(s,e,c,u,d,f){return l(),a("div",null,e[0]||(e[0]=[t('<h1 id="如何描述一个化学物质" tabindex="-1">如何描述一个化学物质 <a class="header-anchor" href="#如何描述一个化学物质" aria-label="Permalink to &quot;如何描述一个化学物质&quot;">​</a></h1><blockquote><p>描述/表达一个化学物质的方法有：</p></blockquote><ol><li>化学名称：根据常见化合名称和有机化合物命名规则</li><li>化学物质编码</li><li>化学结构式：可视化、图片文件格式</li><li>特定格式的化学体系结构文件：如CDXML格式，CDX格式，cml格式，MOL格式，SKC格式，是化学结构式的存储形式</li><li>定义一些规则，使用文本格式、线性记法表示化学结构：为了在文本中快速存储与表达结构式，比如在数据库文本字段中存储，在简单文本中传递化学物质结构。例如SMILES、InChI</li></ol><h2 id="化学物质编码" tabindex="-1">化学物质编码 <a class="header-anchor" href="#化学物质编码" aria-label="Permalink to &quot;化学物质编码&quot;">​</a></h2><h3 id="cas" tabindex="-1">CAS <a class="header-anchor" href="#cas" aria-label="Permalink to &quot;CAS&quot;">​</a></h3><ul><li>美国化学会的下设组织：美国化学文摘社（Chemical Abstract Service，CAS）。负责为每一种出现在文献中的物质分配一个CAS号，其目的是为了避免化学物质有多种名称的麻烦，使数据库的检索更为方便。如今几乎所有的化学数据库都支持CAS号检索。</li><li>CAS号（CAS Registry Number或称CAS Number，CAS Rn，CAS #），又称CAS登记号，是某种物质（化合物、高分子材料、生物序列（Biologicalsequences）、混合物或合金）的<strong>唯一的数字识别号码</strong>。该号是用来判定检索有多个名称的化学物质信息的重要工具。编号由3部分数字组成，各部分之间由短线联接。第一部分有2到7位数字，第二部分有2位数字，第三部分有1位数字作为校验码。</li><li><img src="'+i+'" alt="1736149676339"></li></ul><h3 id="un号" tabindex="-1">UN号 <a class="header-anchor" href="#un号" aria-label="Permalink to &quot;UN号&quot;">​</a></h3><p>联合国（United Nations）编号（联合国危险货物运输专家委员会编号），也称作危险品运输编号，是联合国危险货物运输专家委员会对危险物质制定的编号。UN编号登录在联合国《关于危险货物运输的建议书》（Recommendations on the Transport of Dangerous Goods）中。</p><h3 id="einecs登录号-又称ec编号" tabindex="-1">EINECS登录号（又称EC编号） <a class="header-anchor" href="#einecs登录号-又称ec编号" aria-label="Permalink to &quot;EINECS登录号（又称EC编号）&quot;">​</a></h3><p>欧洲经济共同体(European Community)的《欧洲现有商业化学品目录》(European Inventory of Existing commercial Chemical Substances)中对该化学品的登录编号。</p><h3 id="elincs登录号" tabindex="-1">ELINCS登录号 <a class="header-anchor" href="#elincs登录号" aria-label="Permalink to &quot;ELINCS登录号&quot;">​</a></h3><p>《欧洲已申报化学品目录》(European List of Notified Chemical Substances)的登录编号，由欧盟化学品管理署（ECHA）及欧盟各成员国发布并管理，共收录物质5292种。</p><h3 id="icsc编号" tabindex="-1">ICSC编号 <a class="header-anchor" href="#icsc编号" aria-label="Permalink to &quot;ICSC编号&quot;">​</a></h3><p>国际化学品安全卡International Chemical Safety Card，是由世界卫生组织(WHO)、国际劳工组织(ILO)和联合国环境规划署(UNEP)三个组织的合作机构--国际化学品安全规划署(IPCS)与欧洲联盟委员会(CEU)合作编辑的一套化学品安全信息卡片。国际化学品安全卡ICSC(International Chemical Safety Cards) 共设有化学品标识、危害/接触类型、急性危害/症状、预防、急救/消防、溢漏处置、包装与标志、应急响应、储存、重要数据、物理性质、环境数据、注解和附加资料14个项目。</p><h3 id="rtecs号" tabindex="-1">RTECS号 <a class="header-anchor" href="#rtecs号" aria-label="Permalink to &quot;RTECS号&quot;">​</a></h3><p>化学物质毒性作用登记号Registry of Toxic Effects of Chemical Substances，是美国职业安全与卫生研究所规定的登记号，可用来查找一种化学物质的毒理学数据。RTECS中主要包括以下六大类化学物质的毒性数据：直接刺激性（Primary irritation）、致突变性（Mutagenic effects）、对生殖的影响（Reproductive effects，即致畸性）、致肿瘤性（Tumorigenic effects）、急性毒性（Acute toxicity）、其他多剂量毒性。其中记录有该化学物质的数值毒性值，如半数致死量（LD50或LC50），最低中毒剂量（TDLo），最低中毒浓度（TCLo）等，以及实验所使用的物种和给药途径。</p><h3 id="其它" tabindex="-1">其它 <a class="header-anchor" href="#其它" aria-label="Permalink to &quot;其它&quot;">​</a></h3><ul><li>IMDG：International Maritime Dangerous Goods（国际海运危险货物）</li><li>危险货物编号：CN号，China DG Number，DG即DangerousGoods，《GB12268-90危险货物品名表》的危险货物编号</li><li>HS编码即海关编码：《商品名称及编码协调制度的国际公约》（International Convention for Harmonized Commodity Deionand Coding System）简称协调制度</li><li>MDL号是每一种化学反应和变化的唯一识别号</li><li><a href="https://lab.jgvogel.cn/c/2022-05-10/1180718.shtml" target="_blank" rel="noreferrer">化合物的编码: CAS号、UN号、ES号</a></li></ul><h2 id="化学物质标识符" tabindex="-1">化学物质标识符 <a class="header-anchor" href="#化学物质标识符" aria-label="Permalink to &quot;化学物质标识符&quot;">​</a></h2><h3 id="smiles" tabindex="-1">SMILES <a class="header-anchor" href="#smiles" aria-label="Permalink to &quot;SMILES&quot;">​</a></h3><ul><li>Simplified molecular input line entry system，简化分子线性输入规范，是一种用ASCII字符串明确描述分子结构的规范。</li><li>SMILES字符串可以被大多数分子编辑软件导入并转换成二维图形或分子的三维模型。</li></ul><h3 id="inchi" tabindex="-1">InChI <a class="header-anchor" href="#inchi" aria-label="Permalink to &quot;InChI&quot;">​</a></h3><ul><li>The International Chemical Identifier，国际化合物标识，IUPAC和InChi-Trust开发，用以唯一标识化合物IUPAC名称的字符串。</li><li>一种表示化学分子结构的工具，主要用于数据库、便于检索和分析</li><li>官网：<a href="https://www.inchi-trust.org/" target="_blank" rel="noreferrer">InChI Trust – InChI: structure-based chemical identifier (inchi-trust.org)</a></li></ul><h2 id="化学体系结构文件" tabindex="-1">化学体系结构文件 <a class="header-anchor" href="#化学体系结构文件" aria-label="Permalink to &quot;化学体系结构文件&quot;">​</a></h2><h3 id="格式" tabindex="-1">格式 <a class="header-anchor" href="#格式" aria-label="Permalink to &quot;格式&quot;">​</a></h3><ul><li>以文本文件形式描述化学物质, 不同的格式编写规则不同, <strong>以文件后缀区分</strong></li><li>大部分小分子结构可以从Pubchem或Chemspider等数据库里面下载sdf或者pdb格式的2D/3D结构文件，大分子结构可以从PDB数据库下载pdb</li><li>新合成的化合物没有收录进数据库，可以使用Chemdraw进行绘制，通过经典化学构图方法对小分子化合物进行结构构建后，采用量化软件(Gaussian，ORCA等)计算分子电荷分布、分子轨道和反应活化能等对小分子进行结构优化</li><li>小分子常用sdf、mol2；大分子常用pdb</li></ul><h3 id="pdb" tabindex="-1">pdb <a class="header-anchor" href="#pdb" aria-label="Permalink to &quot;pdb&quot;">​</a></h3><ul><li>来自PDB(Protein Data Bank)，是一种标准文件格式, 其中包含原子的坐标等信息, 提交给 Protein Data Bank at the Research Collaboratory for Structural Bioinformatics (RCSB) 的结构都使用这种标准格式.</li><li>常用于蛋白质结构，但可以用于其他类型的分子</li><li>完整的PDB文件提供了非常多的信息, 包括作者, 参考文献以及结构说明, 如二硫键, 螺旋, 片层, 活性位点. 在使用PDB文件时请记住, 一些建模软件可能不支持那些错误的输入格式.</li><li>PDB格式以文本格式给出信息, 每一行信息称为一个 <strong>记录(record)</strong>. 一个PDB文件通常包括很多不同类型的记录, 它们以特定的顺序排列, 用以描述结构.</li><li><a href="https://blog.csdn.net/weixin_40013463/article/details/81735304" target="_blank" rel="noreferrer">PDB(Protein Data Bank)数据格式详解-CSDN博客</a></li><li><a href="https://www.wwpdb.org/documentation/file-format-content/format33/v3.3.html" target="_blank" rel="noreferrer">Atomic Coordinate Entry Format Version 3.3</a></li><li>需要创建PDB文件的用户, 请参考<a href="http://www.wwpdb.org/documentation/file-format" target="_blank" rel="noreferrer">PDB格式官方文档</a>.</li></ul><h3 id="sdf" tabindex="-1">sdf <a class="header-anchor" href="#sdf" aria-label="Permalink to &quot;sdf&quot;">​</a></h3><ul><li>SDF文件（Structure Data File）是一种用于存储结构化数据的文件格式。由Tripos公司开发的一种标准格式，被广泛应用于药物设计、分子建模等领域</li><li>SDF文件能够包含分子的结构式、化学信息和物理属性等多种数据。通常用于化学、生物、药物等领域中，用于描述分子结构、蛋白质序列、化合物属性等数据。</li><li>Pubchem或Chemspider可以下载sdf文件</li></ul><h3 id="psf" tabindex="-1">psf <a class="header-anchor" href="#psf" aria-label="Permalink to &quot;psf&quot;">​</a></h3><ul><li>PSF文件（protein structure file），用来描述分子拓扑结构的文件格式</li><li><a href="https://www.ks.uiuc.edu/Training/Tutorials/namd/namd-tutorial-unix-html/node23.html" target="_blank" rel="noreferrer">PSF Files (uiuc.edu)</a></li></ul><h3 id="mol和mol2" tabindex="-1">mol和mol2 <a class="header-anchor" href="#mol和mol2" aria-label="Permalink to &quot;mol和mol2&quot;">​</a></h3><ul><li>mol 保存有关分子的原子、键、连通性和坐标的信息</li><li><a href="https://www.cnblogs.com/aobaxu/p/17371835.html" target="_blank" rel="noreferrer">mol 文件格式简单解析（v2000）-博客园(cnblogs.com)</a></li><li>ChemDraw、Avogadro可以导出mol格式</li><li><strong>mol2 文件</strong>是一种扩展的mol文件，除了包含拓扑结构和坐标信息外，还包含了原子的电荷、类型和描述等更详细的信息。</li><li>VMD、GaussView、Chem3D、OpenBabel、AutoDock、Sybyl、AmberTools里的Antechamber等程序可以导出mol2文件</li><li><a href="http://bbs.keinsci.com/thread-34520-1-1.html" target="_blank" rel="noreferrer">化学体系结构的mol2文件 - 计算化学公社 (keinsci.com)</a></li></ul><h3 id="cif" tabindex="-1">cif <a class="header-anchor" href="#cif" aria-label="Permalink to &quot;cif&quot;">​</a></h3><ul><li>CIF(Crystallographic Information File)格式广泛用于记录晶体结构数据，包括空间群信息、原子坐标等，对于材料科学和晶体化学研究者极为重要</li></ul><h3 id="xyz" tabindex="-1">xyz <a class="header-anchor" href="#xyz" aria-label="Permalink to &quot;xyz&quot;">​</a></h3><ul><li><a href="http://sobereva.com/477" target="_blank" rel="noreferrer">记录化学体系结构的xyz文件 - (sobereva.com)</a></li></ul><h3 id="gro" tabindex="-1">gro <a class="header-anchor" href="#gro" aria-label="Permalink to &quot;gro&quot;">​</a></h3><ul><li>来自分子模拟软件包GROMACS，专用于存储分子动力学模拟的输出，类似于PDB格式</li></ul><h3 id="可视化" tabindex="-1">可视化 <a class="header-anchor" href="#可视化" aria-label="Permalink to &quot;可视化&quot;">​</a></h3><p>读取并可视化化学物质结构文件的常用软件有</p><ul><li>PyMOL：支持pdb、cif、xyz格式</li><li>VMD: 支持多种格式</li><li>UCSF Chimera</li><li>VESTA: 晶体文件</li><li>Materials Studio 的 Materials Visualizer 模块</li><li>Chemdraw: 绘制分子</li><li>Avogadro</li><li>PDB官网提供在线的pdb文件浏览和查询功能</li></ul><div class="warning custom-block"><p class="custom-block-title">注意</p><p>这些结构文件本质都是文本文件，可以用文本编辑器查看</p></div><h3 id="格式转换" tabindex="-1">格式转换 <a class="header-anchor" href="#格式转换" aria-label="Permalink to &quot;格式转换&quot;">​</a></h3><ul><li>可以通过MS、VMD、Open Babel等多种软件进行格式转换</li><li>OpenBabel，开源免费的化学专家系统，化学文件格式转换工具</li><li><a href="https://openbabel.org/" target="_blank" rel="noreferrer">Open Babel - the chemistry toolbox — Open Babel openbabel-3-1-1 documentation</a></li><li><a href="https://github.com/openbabel/openbabel/releases" target="_blank" rel="noreferrer">Releases · openbabel/openbabel · GitHub</a></li></ul><h2 id="化学物质数据库" tabindex="-1">化学物质数据库 <a class="header-anchor" href="#化学物质数据库" aria-label="Permalink to &quot;化学物质数据库&quot;">​</a></h2><h3 id="药物" tabindex="-1">药物 <a class="header-anchor" href="#药物" aria-label="Permalink to &quot;药物&quot;">​</a></h3><ul><li><a href="https://pubchem.ncbi.nlm.nih.gov/" target="_blank" rel="noreferrer">PubChem (nih.gov)</a></li><li><a href="https://zhuanlan.zhihu.com/p/534534896" target="_blank" rel="noreferrer">万字长文：如何玩转PubChem数据库 - 知乎 (zhihu.com)</a></li><li>商业化：<a href="https://zinc.docking.org/" target="_blank" rel="noreferrer">ZINC (docking.org)</a></li><li><a href="https://www.drugfuture.com/Organic_Name_Reactions/index.html" target="_blank" rel="noreferrer">Organic Name Reactions (drugfuture.com)</a>人名反应的反应机理、参考文献</li><li><a href="https://www.drugfuture.com/synth/synth_query.asp" target="_blank" rel="noreferrer">药物合成路线数据库--Drug Future药物在线</a></li><li><a href="https://www.drugfuture.com/chemdata/index.aspx" target="_blank" rel="noreferrer">化学物质索引数据库（Chemical Index Database） (drugfuture.com)</a></li><li><a href="https://www.chemblink.com/" target="_blank" rel="noreferrer">chemBlink - Chemical Database, CAS #, SDS and suppliers</a></li><li><a href="https://www.drugfuture.com/toxic/" target="_blank" rel="noreferrer">化学物质毒性数据库(Chemical Toxicity Database) (drugfuture.com)</a></li><li><a href="https://pharmacy.medpeer.cn/" target="_blank" rel="noreferrer">药物研究 (medpeer.cn)</a></li><li><a href="https://www.drugs.com/" target="_blank" rel="noreferrer">Drugs.com - Prescription Drug Information</a>提供超过 24,000 种处方药和非处方药的详细和准确信息</li><li><a href="https://www.drugfuture.com/fda/" target="_blank" rel="noreferrer">美国FDA药品数据库（U.S. FDA Drugs Database） (drugfuture.com)</a></li><li><a href="https://www.drugfuture.com/cndrug/" target="_blank" rel="noreferrer">中国药品注册数据库(Chinese Marketed Drugs Database) (drugfuture.com)</a></li><li><a href="https://www.drugfuture.com/fda/IIG_query.aspx" target="_blank" rel="noreferrer">美国FDA批准药物非活性成分数据库 (drugfuture.com)</a></li><li><a href="https://www.registrarcorp.com/" target="_blank" rel="noreferrer">Home - Registrar (registrarcorp.com)</a>FDA药品注册法规</li><li><a href="https://go.drugbank.com/" target="_blank" rel="noreferrer">DrugBank Online | Database for Drug and Drug Target Info</a></li><li><a href="https://www.drugfuture.com/excipients/browser.html" target="_blank" rel="noreferrer">药用辅料手册(Handbook of Pharmaceutical Excipients) (drugfuture.com)</a></li><li><a href="https://www.drugfuture.com/standard/index.html" target="_blank" rel="noreferrer">药品标准查询-药典在线-药物在线数据库 (drugfuture.com)</a></li><li><a href="https://www.ich.org/" target="_blank" rel="noreferrer">ICH Official web site : ICH</a>国际人用药品注册技术协调会</li><li><a href="https://www.drugfuture.com/Pharmacopoeia/usp32/" target="_blank" rel="noreferrer">美国药典在线(United States Pharmacopoeia) (drugfuture.com)</a></li><li><a href="https://www.usp.org/" target="_blank" rel="noreferrer">US Pharmacopeia (USP)</a></li><li><a href="https://www.edqm.eu/en/home" target="_blank" rel="noreferrer">European Directorate for the Quality of Medicines and Healthcare - European Directorate for the Quality of Medicines HealthCare (edqm.eu)</a></li><li><a href="https://www.chp.org.cn/" target="_blank" rel="noreferrer">国家药典委员会 官方网站 - 国家药典委员会 (chp.org.cn)</a></li><li><a href="https://www.fda.gov/" target="_blank" rel="noreferrer">U.S. Food and Drug Administration (fda.gov)</a></li><li><a href="https://www.ema.europa.eu/en" target="_blank" rel="noreferrer">European Medicines Agency | (europa.eu)</a></li><li><a href="https://www.nmpa.gov.cn/" target="_blank" rel="noreferrer">国家药品监督管理局 (nmpa.gov.cn)</a></li><li><a href="https://www.cde.org.cn/" target="_blank" rel="noreferrer">国家药品监督管理局药品审评中心 (cde.org.cn)</a></li><li><a href="https://zhuanlan.zhihu.com/p/551842489" target="_blank" rel="noreferrer">药学领域的免费数据库</a><ul><li>[1] <a href="https://www.chemdrug.com/news/231/12/58379.html" target="_blank" rel="noreferrer">https://www.chemdrug.com/news/231/12/58379.html</a></li><li>[2] <a href="https://www.drugfuture.com/fda/drugview/202811" target="_blank" rel="noreferrer">https://www.drugfuture.com/fda/drugview/202811</a></li><li>[3] <a href="https://www.medchemexpress.cn/" target="_blank" rel="noreferrer">https://www.medchemexpress.cn/</a></li><li>[4] <a href="https://www.fda.gov/media/83975/download" target="_blank" rel="noreferrer">https://www.fda.gov/media/83975/download</a></li><li>[5] <a href="https://www.drugs.com/linzess.html" target="_blank" rel="noreferrer">https://www.drugs.com/linzess.html</a></li><li>[6] <a href="http://cheman.chemnet.com/#" target="_blank" rel="noreferrer">http://cheman.chemnet.com/#</a></li></ul></li></ul><h3 id="蛋白质" tabindex="-1">蛋白质 <a class="header-anchor" href="#蛋白质" aria-label="Permalink to &quot;蛋白质&quot;">​</a></h3><ul><li>Uniprot: 世界领先的高质量、全面且可免费访问的蛋白质序列和功能信息资源: <a href="https://www.uniprot.org/" target="_blank" rel="noreferrer">UniProt</a></li><li>蛋白质核酸数据库：PDB(全称Protein Data Bank,简称PDB数据库)是美国Brookhaven国家实验室于1971年创建的,由结构生物信息学研究合作组织(Research Collaboratory for Structural Bioinformatics,简称RCSB)维护</li></ul><h3 id="核酸" tabindex="-1">核酸 <a class="header-anchor" href="#核酸" aria-label="Permalink to &quot;核酸&quot;">​</a></h3><ul><li>基因和基因组百科全书: <a href="https://www.genome.jp/kegg/" target="_blank" rel="noreferrer">KEGG: Kyoto Encyclopedia of Genes and Genomes</a></li><li><a href="https://www.genome.jp/kegg/" target="_blank" rel="noreferrer">人类基因数据库</a><a href="https://www.genecards.org/" target="_blank" rel="noreferrer">GeneCards - Human Genes | Gene Database | Gene Search</a></li><li><a href="https://www.genecards.org/" target="_blank" rel="noreferrer">基因功能信息来源</a><a href="http://geneontology.org/" target="_blank" rel="noreferrer">Gene Ontology Resource</a></li></ul><h3 id="晶体" tabindex="-1">晶体 <a class="header-anchor" href="#晶体" aria-label="Permalink to &quot;晶体&quot;">​</a></h3><ul><li>有机、无机、金属有机化合物和矿物（不包括生物聚合物）<a href="https://www.crystallography.net/cod/" target="_blank" rel="noreferrer">Crystallography Open Database</a></li><li><a href="https://home.deds.nl/~crystal/index.html" target="_blank" rel="noreferrer">晶体之星晶体结构网,Crystal Structure Web (deds.nl)</a></li><li><img src="'+o+'" alt="1737202214559"></li><li>CCDC-CSD <ul><li>Cambridge Structural Database (CSD，剑桥晶体结构数据库)：由剑桥晶体数据中心 (CCDC, Cambridge Crystallographic Data Centre)管理和维护，基于 X 光和中子衍射实验唯一的小分子及金属有机分子晶体的结构数据库，基本上包括已发表的所有原子个数 (包括氢原子)在 500 以内的有机及金属有机化合物晶体数据。随着 PDB和NDB(Nucleic Acid Database)快速发展，CSD 不再包括低核苷酸的数据，但增加了高分子的数据。</li><li>官网：<a href="https://www.ccdc.cam.ac.uk/" target="_blank" rel="noreferrer">Advancing Structural Science | CCDC (cam.ac.uk)</a></li><li>结构搜索：<a href="https://www.ccdc.cam.ac.uk/structures/" target="_blank" rel="noreferrer">Search - Access Structures (cam.ac.uk)</a></li></ul></li><li>ICSD: 无机晶体结构数据库（Inorganic Crystal Structure Database），由德国FIZ Karlsruhe 提供的世界上最大的无机晶体结构数据库 <ul><li>官网：<a href="https://icsd.products.fiz-karlsruhe.de/" target="_blank" rel="noreferrer">Home | ICSD (fiz-karlsruhe.de)</a></li></ul></li><li><a href="https://www.rcsb.org/" target="_blank" rel="noreferrer">RCSB PDB: Homepage</a></li></ul><h3 id="icdd-pdf-数据库" tabindex="-1">ICDD-PDF 数据库 <a class="header-anchor" href="#icdd-pdf-数据库" aria-label="Permalink to &quot;ICDD-PDF 数据库&quot;">​</a></h3><p>国际衍射数据中心（The International Centre for Diffraction Data），包含PDF数据库和JADE分析工具 PDF Cards：</p><h3 id="中药" tabindex="-1">中药 <a class="header-anchor" href="#中药" aria-label="Permalink to &quot;中药&quot;">​</a></h3><ul><li><a href="https://news.sohu.com/a/579746073_120604618" target="_blank" rel="noreferrer">中医药科研数据集成_临床_植物_药理学 (sohu.com)</a></li><li><a href="https://blog.csdn.net/Yiyaoshujuku/article/details/129620761" target="_blank" rel="noreferrer">除中国中医药数据库官网外-必备5个其它常用中国中医药数据库-CSDN博客</a></li><li><a href="https://www.zysj.com.cn/" target="_blank" rel="noreferrer">中医世家 (zysj.com.cn)</a></li></ul><h3 id="有机物" tabindex="-1">有机物 <a class="header-anchor" href="#有机物" aria-label="Permalink to &quot;有机物&quot;">​</a></h3><p><strong>Beilstein 贝尔斯坦数据库</strong>：是有机化学领域最大的数据库，其中的化合物通过其Beilstein 登记号进行唯一标识。</p>',61)]))}const g=r(n,[["render",h]]);export{b as __pageData,g as default};
